@page "/board"
@using sv_54f6bb22fe3e450b92f932fba6e0f24b.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Summary Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item">Total: @allTasks.Count</span>
        <span class="stat-item">To Do: @GetColumnTasks("To Do").Count</span>
        <span class="stat-item">In Progress: @GetColumnTasks("In Progress").Count</span>
        <span class="stat-item">Done: @GetColumnTasks("Done").Count</span>
        <span class="stat-item stat-overdue">Overdue: @allTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board-container">
        @foreach (var status in columns)
        {
            var columnTasks = GetFilteredColumnTasks(status);
            <div class="board-column">
                <div class="column-header">
                    <h4>@status (@columnTasks.Count)</h4>
                </div>
                <div class="column-body">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(status) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[GetColumnIndex(status) - 1])"
                                            disabled="@isMoving">
                                        &larr; Move Left
                                    </button>
                                }
                                @if (GetColumnIndex(status) < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[GetColumnIndex(status) + 1])"
                                            disabled="@isMoving">
                                        Move Right &rarr;
                                    </button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (addingToColumn == status)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control mb-1" placeholder="Title" @bind="newTitle" />
                        <input type="text" class="form-control mb-1" placeholder="Assignee" @bind="newAssignee" />
                        <select class="form-select mb-1" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control mb-1" @bind="newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="() => SaveTaskAsync(status)" disabled="@isSaving">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn" @onclick="() => ShowAddForm(status)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private bool isMoving;
    private bool isSaving;
    private string? errorMessage;
    private string searchText = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchText) ||
                         t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private int GetColumnIndex(string status) => Array.IndexOf(columns, status);

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            isMoving = false;
        }
    }

    private void ShowAddForm(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveTaskAsync(string status)
    {
        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            // CreateTaskAsync returns a task with default status; override to match target column
            allTasks.Add(created with { Status = status });
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }
}

